-- Draw a triangle in the centre of the screen. 
render.drawPoly( { 
	-- Top vertex, u = 0.5 as it's halfway along the width of the shape. 
	{ x = 256, y = 256 - 64, u = 0.5, v = 0 }, 
	-- Bottom right vertex. u = 1 as it's the full width along, v = 1 as it's the full height *down*. 
	{ x = 256 + 64, y = 256 + 64, u = 1, v = 1 }, 
	-- Bottom left vertex. u = 0 as it's the very left-most point, v = 1 as it's still the bottom. 
	{ x = 256 - 64, y = 256 + 64, u = 0, v = 1 } 
} )
